import type { Metadata } from "next";
import Image from "next/image";
import Link from "next/link";
import { notFound } from "next/navigation";

import Prose from "@/components/prose";
import { decodeHtmlEntities } from "@/lib/html";
import { readImportedPage, readImportedPost } from "@/lib/local-content";

const RESERVED = new Set(["about", "category", "post", "api", "_next", "favicon.ico"]);

export async function generateMetadata({
    params,
}: {
    params: Promise<{ slug: string }>;
}): Promise<Metadata> {
    const { slug } = await params;
    if (RESERVED.has(slug)) return {};

    const item = readImportedPost(slug) ?? readImportedPage(slug);
    if (!item) return { title: "Not found" };

    return {
        title: decodeHtmlEntities(item.title ?? "Untitled"),
        description: item.description ?? undefined,
    };
}

export default async function SlugPage({
    params,
}: {
    params: Promise<{ slug: string }>;
}) {
    const { slug } = await params;
    if (RESERVED.has(slug)) notFound();

    const post = readImportedPost(slug);
    const page = post ? null : readImportedPage(slug);
    const item = post ?? page;

    if (!item) {
        return (
            <div className="mx-auto flex w-full max-w-3xl flex-col gap-6">
                <h1 className="text-2xl font-semibold tracking-tight">Content not found yet</h1>
                <p className="text-[color:var(--muted)]">
                    You chose an offline rebuild. Run the importer to download all posts/pages and images into the project.
                </p>
                <div className="surface-strong rounded-2xl p-4 text-sm text-[color:var(--muted)]">
                    <p className="font-medium text-[var(--foreground)]">Importer command</p>
                    <p className="mt-2 font-mono">node .\\scripts\\import-financialedge.mjs</p>
                </div>
                <Link href="/" className="text-sm font-medium text-[color:var(--muted)] hover:text-[var(--foreground)]">
                    Back home
                </Link>
            </div>
        );
    }

    const title = decodeHtmlEntities(item.title ?? "Untitled");

    return (
        <div className="mx-auto flex w-full max-w-4xl flex-col gap-8">
            <div className="flex flex-col gap-3">
                <div className="flex flex-wrap items-center justify-between gap-3">
                    <Link
                        href="/"
                        className="text-sm font-semibold text-[color:var(--brand)] hover:opacity-90"
                    >
                        ← Back home
                    </Link>
                    {item.sectionSlug ? (
                        <Link
                            href={`/category/${item.sectionSlug}`}
                            className="text-sm font-semibold text-[color:var(--brand)] hover:opacity-90"
                        >
                            View category
                        </Link>
                    ) : null}
                </div>

                <section className="card animate-fe-fade-up overflow-hidden rounded-[28px] p-6 md:p-8">
                    <div className="flex flex-wrap items-center gap-2">
                        {item.section ? (
                            <span className="rounded-full bg-[rgba(11,87,208,0.08)] px-3 py-1 text-xs font-semibold text-[color:var(--brand)]">
                                {item.section}
                            </span>
                        ) : null}
                        {item.publishedAt ? (
                            <span className="text-xs font-medium text-[color:var(--muted)]">
                                {new Date(item.publishedAt).toLocaleDateString(undefined, {
                                    year: "numeric",
                                    month: "long",
                                    day: "numeric",
                                })}
                            </span>
                        ) : null}
                    </div>

                    <h1 className="mt-4 text-3xl font-semibold leading-tight tracking-tight md:text-4xl">
                        {title}
                    </h1>

                    {item.description ? (
                        <p className="mt-3 max-w-3xl text-sm leading-6 text-[color:var(--muted)]">
                            {decodeHtmlEntities(item.description)}
                        </p>
                    ) : null}
                </section>
            </div>

            {item.featuredImage ? (
                <div className="card animate-fe-fade-up overflow-hidden rounded-[28px]">
                    <div className="relative aspect-[16/9] w-full bg-zinc-100">
                        <Image
                            src={item.featuredImage}
                            alt={title}
                            fill
                            className="object-cover"
                            sizes="(max-width: 1024px) 100vw, 896px"
                            priority={false}
                        />
                    </div>
                </div>
            ) : null}

            <div className="card animate-fe-fade-up overflow-hidden rounded-[28px] p-6 md:p-8">
                <Prose>
                    <div dangerouslySetInnerHTML={{ __html: item.html }} />
                </Prose>
            </div>
        </div>
    );
}
